alter table public.coding_plans
  add column if not exists section text not null default 'legacy',
  add column if not exists plan_name text,
  add column if not exists model_name text,
  add column if not exists official_note text,
  add column if not exists note text,
  add column if not exists usage_type text,
  add column if not exists requests_tokens_5h text,
  add column if not exists value_5h text,
  add column if not exists ratio_5h text,
  add column if not exists requests_tokens_week text,
  add column if not exists value_week text,
  add column if not exists ratio_week text,
  add column if not exists requests_tokens_month text,
  add column if not exists value_month text,
  add column if not exists ratio_month text,
  add column if not exists sort_order integer not null default 100;

create index if not exists idx_coding_plans_section_sort
on public.coding_plans(section, sort_order);

update public.categories
set count = 27,
    updated_at = now()
where key = 'coding';

